export function getStopById(id: string, page: "city" | "country" = "city"): BusStop | undefined {
  return page === "city"
    ? cityStops.find(s => s.id === id)
    : countryStops.find(s => s.id === id);
}

export function getRouteById(id: string, page: "city" | "country" = "city"): BusRoute | undefined {
  return page === "city"
    ? cityRoutes.find(r => r.id === id)
    : countryRoutes.find(r => r.id === id);
}

export function searchStops(query: string, page: "city" | "country" = "city"): BusStop[] {
  if (!query || query.length < 1) return [];
  const q = query.toLowerCase().trim();
  const pool = page === "city" ? cityStops : countryStops;
  return pool.filter(s => s.name.toLowerCase().includes(q)).slice(0, 8);
}

export function getRoutesForStop(stopId: string, page: "city" | "country" = "city"): BusRoute[] {
  const stop = getStopById(stopId, page);
  if (!stop) return [];
  const pool = page === "city" ? cityRoutes : countryRoutes;
  return stop.routes.map(r => pool.find(rt => rt.id === r)).filter(Boolean) as BusRoute[];
}

export function findRoutesBetweenStops(startId: string, endId: string, page: "city" | "country" = "city"): BusRoute[] {
  const pool = page === "city" ? cityRoutes : countryRoutes;
  return pool.filter(route => {
    const ids = route.stops.map(s => s.stopId);
    const si = ids.indexOf(startId);
    const ei = ids.indexOf(endId);
    return si !== -1 && ei !== -1 && si < ei;
  });
}
